import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getLoggedInUser } from "../auth";

function EmployeeOffers() {
  const navigate = useNavigate();
  const user = getLoggedInUser();
  const [offers, setOffers] = useState([]);

  useEffect(() => {
    const allOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    // 🔥 FIX: Default status = SENT if missing
    const normalizedOffers = allOffers.map((o) => ({
      ...o,
      status: o.status || "SENT"
    }));

    localStorage.setItem(
      "offerLetters",
      JSON.stringify(normalizedOffers)
    );

    const myOffers = normalizedOffers.filter(
      (o) => o.email === user?.email
    );

    setOffers(myOffers);
  }, [user]);

  const updateStatus = (applicationId, status) => {
    const allOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const updated = allOffers.map((o) =>
      o.applicationId === applicationId
        ? { ...o, status }
        : o
    );

    localStorage.setItem(
      "offerLetters",
      JSON.stringify(updated)
    );

    setOffers(updated.filter((o) => o.email === user?.email));

    alert(`Offer ${status}`);
  };

  if (offers.length === 0) {
    return (
      <div style={{ marginTop: "25px" }}>
        <h2>My Job Offers</h2>
        <p>No offers received yet.</p>
      </div>
    );
  }

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>My Job Offers</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Job Title</th>
            <th>Salary</th>
            <th>Joining Date</th>
            <th>Location</th>
            <th>Status</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {offers.map((o, i) => (
            <tr key={o.applicationId}>
              <td>{i + 1}</td>
              <td>{o.jobTitle}</td>
              <td>₹{o.salary}</td>
              <td>{o.joiningDate}</td>
              <td>{o.location}</td>
              <td>{o.status}</td>

              <td style={{ display: "flex", gap: "8px" }}>
                <button
                  onClick={() =>
                    navigate(
                      `/dashboard/recruitment/offer-preview/${o.applicationId}`
                    )
                  }
                >
                  View
                </button>

                {/* ✅ Accept / Reject only if SENT */}
                {o.status === "SENT" && (
                  <>
                    <button
                      style={{
                        background: "green",
                        color: "white"
                      }}
                      onClick={() =>
                        updateStatus(o.applicationId, "ACCEPTED")
                      }
                    >
                      Accept
                    </button>

                    <button
                      style={{
                        background: "red",
                        color: "white"
                      }}
                      onClick={() =>
                        updateStatus(o.applicationId, "REJECTED")
                      }
                    >
                      Reject
                    </button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default EmployeeOffers;
